function pathnameToSegments(pathname) {
    const parts = pathname.split('/').filter(Boolean);
    if (parts.length === 0) {
        return [
            {
                label: 'Dashboard',
                href: '/dashboard'
            }
        ];
    }
    let acc = '';
    return parts.map((part)=>{
        acc += '/' + part;
        return {
            label: humanize(decodeURIComponent(part)),
            href: acc
        };
    });
}
